import React from 'react';

const About = () => {
  return (
    <div>
      <h2>About Us</h2>
      <p>About Us
Mac Keating Ltd.
At Mac Keating Ltd., we specialize in crafting cutting-edge software solutions tailored to our clients' needs. As experts in AI systems, we transform visionary ideas into dynamic, functional realities. Our commitment to innovation and excellence drives us to deliver unparalleled software that empowers businesses to thrive in the digital age. </p>
    </div>
  );
};

export default About;
